slides.codeSnippet:
void main() {
  String? optionalMessage = null;

  // This would crash the app if Dart didn't stop us earlier!
  // print(optionalMessage.toUpperCase()); 

  optionalMessage = 'Hello!';

  // Safe Check:
  if (optionalMessage != null) {
    print(optionalMessage.toUpperCase());
  }
}
